import{_ as a,o as s,c as t,a5 as o}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"概念：UPS 保护标志（UPS protection flags）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：UPS 保护标志（UPS protection flags）","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0027-ups-c-protection-flags.html` 的源稿和补充资料。它只使用教学采样序列和教学阈值，不包含公司内部保护阈值、未公开产品方案、客户项目参数或内部测试数据。向导师提问时不能记录公司内部保护阈值，不能记录内部测试数据，不能记录客户项目参数。"},"headers":[],"relativePath":"content/power/concepts/embedded/ups-c-protection-flags.md","filePath":"content/power/concepts/embedded/ups-c-protection-flags.md","lastUpdated":null}'),i={name:"content/power/concepts/embedded/ups-c-protection-flags.md"};function l(n,e,p,c,r,d){return s(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="概念-ups-保护标志-ups-protection-flags" tabindex="-1">概念：UPS 保护标志（UPS protection flags） <a class="header-anchor" href="#概念-ups-保护标志-ups-protection-flags" aria-label="Permalink to &quot;概念：UPS 保护标志（UPS protection flags）&quot;">​</a></h1><p>本页是 <code>lessons/0027-ups-c-protection-flags.html</code> 的源稿和补充资料。它只使用教学采样序列和教学阈值，不包含公司内部保护阈值、未公开产品方案、客户项目参数或内部测试数据。向导师提问时不能记录公司内部保护阈值，不能记录内部测试数据，不能记录客户项目参数。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>UPS 保护标志（UPS protection flags）是把不间断电源（uninterruptible power supply / UPS）的采样值（sampled measurement）和参数表比较后得到的一组布尔结果，例如欠压、过压、旁路不同步和是否需要停机。</p><p>本节只讲一个概念：<code>采样值 + 参数表 -&gt; 保护标志</code>。</p><p>保护标志不是故障锁存（fault latch）。保护标志描述“此刻是否越界”，故障锁存描述“故障是否已经被确认并保持到复位”。本节先讲前者，下一节再讲去抖和锁存。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>UPS 控制软件不能只看控制环路输出。市电异常、直流母线过压、旁路不同步等条件会直接影响模式切换、脉宽调制（pulse-width modulation / PWM）使能和故障锁存。</p><p>如果保护判断分散在状态机、驱动和控制环里，阅读工程时很难知道“这个故障是谁判出来的”。集中保护标志能让你先读清楚保护来源，再看状态机如何消费这些标志。</p><p>采样值先由模数转换器（analog-to-digital converter / ADC）采到原始码，再经采样调理和标定换算成 V、ms 等工程单位。采样值先换算成工程单位，再进入保护判断，这样保护模块才不需要理解 ADC 通道号和比例系数。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>保护模块像值班员。采样模块把电压、同步时间等读数送过来；参数表提供边界；保护模块只回答“是否越界”。状态机和输出模块再决定是否切换模式或关闭执行器。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mains_undervoltage = mains_rms_v &lt; mains_uv_threshold_v</span></span>
<span class="line"><span>dc_bus_overvoltage = dc_bus_v &gt; dc_bus_ov_threshold_v</span></span>
<span class="line"><span>bypass_not_synchronized = bypass_sync_ms &lt; bypass_sync_hold_ms</span></span>
<span class="line"><span>shutdown_required = mains_undervoltage OR dc_bus_overvoltage</span></span></code></pre></div><p>术语：</p><ul><li>欠压保护（undervoltage protection / UVP）</li><li>过压保护（overvoltage protection / OVP）</li><li>旁路不同步（bypass not synchronized）</li><li>控制中断服务程序（control interrupt service routine / control ISR）</li></ul><h2 id="_5-仿真任务与仿真观察" tabindex="-1">5. 仿真任务与仿真观察 <a class="header-anchor" href="#_5-仿真任务与仿真观察" aria-label="Permalink to &quot;5. 仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_protection_flags.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>默认运行时会保存：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/results/ups_protection_flags.png</span></span></code></pre></div><p>图中包含市电 RMS 电压、直流母线电压、旁路同步保持时间、保护标志、阈值线、图例和参数框。默认不加 <code>--no-open</code> 时脚本会尝试自动打开图片；打不开时会打印完整路径。</p><p>同时编译运行 C 骨架后，应能看到：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>protection_flags: mains_uv=1 dc_bus_ov=1 bypass_not_sync=1 shutdown=1</span></span></code></pre></div><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><ul><li><code>UpsMeasurements</code>：采样后换算到工程单位的测量值。</li><li><code>UpsProtectionFlags</code>：保护判断结果。</li><li><code>UpsProtection_Evaluate()</code>：把测量值和 <code>UpsParameters</code> 组合，输出保护标志。</li><li><code>main.c</code>：打印教学保护标志，形成可向导师提问的具体产物。</li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>错误理解：保护就是状态机里多写几个 if。<br> 正确理解：保护判断最好有清楚输入、阈值和输出标志，状态机消费标志。</li><li>错误理解：保护标志只要会触发停机就够了。<br> 正确理解：有些保护触发停机，有些只禁止旁路或降额，需要分层表达。</li><li>错误理解：仿真图只要看最终有没有故障。<br> 正确理解：要看采样量何时跨过阈值，以及保护标志是否同步变化。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能运行 <code>python simulations\\python\\ups_protection_flags.py --no-open</code> 并打开 <code>simulations/results/ups_protection_flags.png</code>。</li><li>能解释市电 RMS、直流母线和旁路同步保持时间分别如何触发保护标志。</li><li>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>，看到 <code>protection_flags</code> 输出。</li><li>能基于 <code>protection.c -&gt; UpsProtection_Evaluate()</code> 准备导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>为什么保护模块应该接收工程单位的采样值，而不是直接接收 ADC 原始码？</li><li>为什么旁路不同步不一定等于系统必须停机？</li><li>如果市电电压在阈值附近抖动，当前教学代码会出现什么问题？</li><li>保护标志和故障锁存的职责差别是什么？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>protection.c -&gt; UpsProtection_Evaluate()</code> 把采样值和参数表集中生成保护标志。真实工程里保护判断通常在控制 ISR、保护任务，还是状态机任务里执行？</li><li>我用 <code>simulations/results/ups_protection_flags.png</code> 看到采样量跨过阈值后标志变为 1。真实工程里保护通常会不会加滤波、去抖或保持时间？</li><li>我不会记录公司内部保护阈值，只想确认组织方式：真实工程里哪些保护会直接停机，哪些只影响旁路或输出许可？</li></ul>`,34)])])}const _=a(i,[["render",l]]);export{u as __pageData,_ as default};
